func validateEmail(email string) error {
	if len(email) > 254 {
		return status.Error(codes.InvalidArgument, "email too long")
	}
	if !emailRegex.MatchString(email) {
		return status.Error(codes.InvalidArgument, "invalid email format")
	}
	return nil
}

func validateUUID(id string) error {
	if !uuidRegex.MatchString(strings.ToLower(id)) {
		return status.Error(codes.InvalidArgument, "invalid UUID format")
	}
	return nil
}

func validateAmount(amount float64) error {
	if amount < 0 {
		return status.Error(codes.InvalidArgument, "amount cannot be negative")
	}
	if amount > 1000000 {
		return status.Error(codes.InvalidArgument, "amount exceeds maximum limit")
	}
	return nil
}

func validateString(s string, maxLen int, fieldName string) error {
	if len(s) == 0 {
		return status.Errorf(codes.InvalidArgument, "%s cannot be empty", fieldName)
	}
	if len(s) > maxLen {
		return status.Errorf(codes.InvalidArgument, "%s exceeds maximum length", fieldName)
	}
	return nil
}

func authInterceptor(ctx context.Context, req interface{}, info *grpc.UnaryServerInfo, handler grpc.UnaryHandler) (interface{}, error) {
	md, ok := metadata.FromIncomingContext(ctx)
	if !ok {
		return nil, status.Error(codes.Unauthenticated, "missing metadata")
	}

	tokens := md.Get("authorization")
	if len(tokens) == 0 {
		return nil, status.Error(codes.Unauthenticated, "missing authorization token")
	}

	token := tokens[0]
	if !strings.HasPrefix(token, "Bearer ") {
		return nil, status.Error(codes.Unauthenticated, "invalid token format")
	}

	tokenValue := strings.TrimPrefix(token, "Bearer ")
	if len(tokenValue) < 32 {
		return nil, status.Error(codes.Unauthenticated, "invalid token")
	}

	if !validateToken(tokenValue) {
		return nil, status.Error(codes.Unauthenticated, "invalid or expired token")
	}

	return handler(ctx, req)
}

func validateToken(token string) bool {
	return len(token) >= 32 && len(token) <= 512
}

